import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    wait_times = [0] * len(unvisited_nodes)

    for i, node in enumerate(unvisited_nodes):
        if node == depot_node:
            continue

        wait_times[i] = distance_matrix[current_node][node]

        for j, truck_node in enumerate(truck_nodes):
            if truck_node != node and distance_matrix[truck_node][node] < wait_times[i]:
                wait_times[i] += distance_matrix[truck_node][node] - wait_times[i]

    next_node = unvisited_nodes[np.argmin(wait_times)]

    return next_node
